#include<bits/stdc++.h>
using namespace std;
long long dp[1010][1010],a[1010][1010];
int main()
{
    int c,t;
    scanf("%d%d",&c,&t);
    while(t--)
    {
        int n,m;
        long long s,k;
        scanf("%d%d%lld%lld",&n,&m,&s,&k);
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=m;j++)
            {
                scanf("%lld",&a[i][j]);
            }
        }
        for(int i=1;i<=m;i++)
        {
            dp[0][i]=s;
        }
        for(int i=1;i<n;i++)
        {
            for(int j=1;j<=m;j++)
            {
                if(dp[i-1][j]<0)
                {
                    dp[i][j]=-1;
                }
                else
                {
                    dp[i][j]=dp[i-1][j]+a[i][j];
                }
            }
            for(int j=2;j<=m;j++)
            {
                if(dp[i][j]>=0&&dp[i][j-1]>=0&&a[i][j-1]+a[i][j]>0)
                {
                    dp[i][j-1]=min(k,max(dp[i][j-1],k+a[i][j-1]));
                    dp[i][j]=min(k,max(dp[i][j],k+a[i][j]));
                }
            }
            for(int l=1;l<=2;l++)
            {
                for(int j=2;j<=m;j++)
                {
                    if(dp[i][j-1]>=0)
                    {
                        dp[i][j]=min(k,max(dp[i][j-1]+a[i][j],dp[i][j]));
                    }
                    if(dp[i][j]>=0&&dp[i][j-1]>=0&&a[i][j-1]+a[i][j]>0)
                    {
                        dp[i][j-1]=min(k,max(dp[i][j-1],k+a[i][j-1]));
                        dp[i][j]=min(k,max(dp[i][j],k+a[i][j]));
                    }
                }
                for(int j=m-1;j>=1;j--)
                {
                    if(dp[i][j+1]>=0)
                    {
                        dp[i][j]=min(k,max(dp[i][j+1]+a[i][j],dp[i][j]));
                    }
                    if(dp[i][j]>=0&&dp[i][j+1]>=0&&a[i][j+1]+a[i][j]>0)
                    {
                        dp[i][j+1]=min(k,max(dp[i][j+1],k+a[i][j+1]));
                        dp[i][j]=min(k,max(dp[i][j],k+a[i][j]));
                    }
                }
            }
        }
        long long ans=-1;
        for(int i=1;i<=m;i++)
        {
            if(dp[n-1][i]>=0)
            {
                ans=max(ans,min(k,dp[n-1][i]+a[n][i]));
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
